import numpy as np

def solve_spd_system(R: np.ndarray, b: np.ndarray) -> np.ndarray:
    n = len(b)
    # Step 1: Forward substitution to solve R^T y = b
    # R^T is lower triangular.
    y = np.zeros(n, dtype=np.float64)
    for i in range(n):
        sum_val = 0.0
        for j in range(i):
            sum_val += R[j, i] * y[j]  # Note: (R^T)_{i,j} = R_{j,i}
        y[i] = (b[i] - sum_val) / R[i, i]

    # Step 2: Backward substitution to solve R x = y
    # R is upper triangular.
    x = np.zeros(n, dtype=np.float64)
    for i in range(n - 1, -1, -1):
        sum_val = 0.0
        for j in range(i + 1, n):
            sum_val += R[i, j] * x[j]
        x[i] = (y[i] - sum_val) / R[i, i]

    return x
